**Issue Description**
We're encountering an issue with OpenSSL's RSA encryption interface where RSA_PKCS1_OAEP_PADDING appears to fall back to RSA_NO_PADDING mode unexpectedly on certain devices.

**Code Sample**
Here's our encryption implementation:

`static zCryptoError EncryptWithPublicKey(EVP_PKEY* evp,DataPair& data)
	{
		if (!evp || !data.IsValidInput())
			return zCryptoError_WrongInput;

		ScopedSSLObj<EVP_PKEY_CTX> ctx(EVP_PKEY_CTX_new(evp, NULL));

		zCryptoError ret = zCryptoError_Success;
		if (!ctx)
		{
			ret = zCryptoError_FailToOpenContext;
			return ret;
		}

		if (EVP_PKEY_encrypt_init(ctx) <= 0)
		{
			ret = zCryptoError_FailToInitContext;
			return ret;
		}

		if (EVP_PKEY_CTX_set_rsa_padding(ctx, RSA_PKCS1_OAEP_PADDING) <= 0)
		{
			ret = zCryptoError_FailToSetPadding;
			return ret;
		}

		size_t target_len = 0;

		if (EVP_PKEY_encrypt(ctx, NULL, &target_len, data._in._base, data._in._len) <= 0)
		{
			ret = zCryptoError_FailToCheckBuffer;
			return ret;
		}

		if (target_len > data._out._len)
		{
			ret = zCryptoError_NeedMoreBuff;
			return ret;
		}

		// out buff size
		size_t out_len = data._out._len;

		int evp_ret = EVP_PKEY_encrypt(ctx, data._out._base, &out_len, data._in._base, data._in._len);
		if (evp_ret <= 0)
		{
			ret = zCryptoError_FailToEncrypt;
			return ret;
		}

		// update encrypted out len
		data._out._len = static_cast<unsigned int>(out_len);

		return zCryptoError_Success;
	}`

